UPDATE tb_user
SET password = #{newPassword},
    update_time = NOW()
WHERE email = #{email}
  AND is_delete = 0

  AND password = #{oldPassword}

UPDATE tb_user
SET avatar_url  = #{avatarUrl},
    update_time = NOW(),
    update_user = #{userId}
WHERE user_id = #{userId}
  AND is_delete = 0

UPDATE tb_user
SET nickname    = #{nickname},
    update_time = NOW(),
    update_user = #{userId}
WHERE user_id = #{userId}
  AND is_delete = 0

UPDATE tb_user
SET is_delete = 1,
    update_time = NOW(),
    update_user = #{userId}
WHERE user_id = #{userId}
  AND is_delete = 0
